package cn.nobeta.dingdong.pay.security;
import com.fasterxml.jackson.core.type.TypeReference;import com.fasterxml.jackson.databind.ObjectMapper;import jakarta.servlet.*;import jakarta.servlet.http.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.http.MediaType;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;import javax.crypto.Mac;import javax.crypto.spec.SecretKeySpec;import java.io.IOException;import java.nio.charset.StandardCharsets;import java.security.MessageDigest;import java.time.Instant;import java.util.*;
@Component public class PayJwtFilter extends OncePerRequestFilter{private final ObjectMapper m;private final byte[] secret;public PayJwtFilter(ObjectMapper m,@Value("${security.jwt.secret:dingdong-change-this-development-secret-at-least-32-bytes}")String s){this.m=m;secret=s.getBytes(StandardCharsets.UTF_8);}@Override protected boolean shouldNotFilter(HttpServletRequest r){return !r.getServletPath().startsWith("/api/");}@Override protected void doFilterInternal(HttpServletRequest q,HttpServletResponse r,FilterChain c)throws ServletException,IOException{String h=q.getHeader("Authorization");if(h==null||!h.startsWith("Bearer ")){deny(r);return;}try{Map<String,Object>x=parse(h.substring(7));PayUserContext.set(new CurrentPayUser(((Number)x.get("sub")).longValue(),(String)x.get("role")));c.doFilter(q,r);}catch(Exception e){deny(r);}finally{PayUserContext.clear();}}private Map<String,Object>parse(String t)throws Exception{String[]p=t.split("\\.");if(p.length!=3||!MessageDigest.isEqual(Base64.getUrlDecoder().decode(p[2]),sign(p[0]+"."+p[1])))throw new IllegalArgumentException();Map<String,Object>x=m.readValue(Base64.getUrlDecoder().decode(p[1]),new TypeReference<>(){});if(Instant.now().getEpochSecond()>=((Number)x.get("exp")).longValue())throw new IllegalArgumentException();return x;}private byte[]sign(String t)throws Exception{Mac x=Mac.getInstance("HmacSHA256");x.init(new SecretKeySpec(secret,"HmacSHA256"));return x.doFinal(t.getBytes(StandardCharsets.UTF_8));}private void deny(HttpServletResponse r)throws IOException{r.setStatus(401);r.setContentType(MediaType.APPLICATION_JSON_VALUE);m.writeValue(r.getWriter(),new Error("AUTH_UNAUTHORIZED","请先登录"));}private record Error(String code,String message){}}
